body:
Any plans to support interfaces in near future?
( at least in very basic form as just bunch of wires for modules connectivity) something like this:

```

// basic interface 
interface tl_if;
logic a_ready;
logic a_valid;
endinterface


// multibus parameterizable interface
interface multi_tl #(CORES=4);
tl_if bus[CORES]();
endinterface

//inner module, connected by the basic interface
module tl_bus_proc(interface tl);
endmodule

// parent  module aka interconnect, containing parameterizable number of inner modules
module llc # (
    parameter CORES = 1,
    parameter SIZE = 3
)
( 
input clk,
interface tls
);

wire aready2 = tls.bus[2].a_ready; 

for(genvar i=0; i<CORES; i++) begin : BP
    tl_bus_proc bp(.tl(tls.bus[i]));
end

tl_if b[2]();
endmodule

//top module, containing N cores with standard interfaces
module top;

wire clk;
for( genvar i = 0, i<=3, i++) begin : CPU
    core core(.tl(tls.bus[i]));
end
multi_tl #3 tls();

llc  #(.CORES(2)) llc0 (.clk(clk), .tls(tls));
llc  #(.CORES(3)) llc1 (.*);
endmodule
```

It is very annoying to type multiple signals standard interfaces and their connections, especially when there are multiple similar interfaces like in the interconnect designs . Also it's kind of hard to make these designs to be parameterized with number of buses...
